float dist(Point p1, Point p2, int dim) {
  int i;
  float result = 0.0;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
#ifdef INSERT_WASTE
  double s = waste(result);
  result += s;
  result -= s;
#endif
  return (result);
}

static void flatten_coords(const Points *points, std::vector<float> &coords) {
  long n = points->num;
  int dim = points->dim;
  coords.resize((size_t)n * (size_t)dim);
  for (long i = 0; i < n; i++) {
    memcpy(&coords[(size_t)i * (size_t)dim], points->p[i].coord, sizeof(float) * dim);
  }
}

__global__ static void pgain_phase1_kernel(const float *coords,
                                           const float *weights,
                                           const float *current_costs,
                                           const long *assigns,
                                           const int *center_table_dev,
                                           long x,
                                           int dim,
                                           long n,
                                           unsigned char *switch_out,
                                           double *costdiff_out,
                                           int *lower_index_out,
                                           double *lower_value_out) {
  long idx = (long)blockIdx.x * (long)blockDim.x + (long)threadIdx.x;
  if (idx >= n)
    return;

  long base = idx * (long)dim;
  long xbase = x * (long)dim;
  float result = 0.0f;
  for (int j = 0; j < dim; j++) {
    float diff = coords[base + j] - coords[xbase + j];
    result += diff * diff;
  }

  float x_cost = result * weights[idx];
  float current_cost = current_costs[idx];

  if (x_cost < current_cost) {
    switch_out[idx] = 1;
    costdiff_out[idx] = (double)x_cost - (double)current_cost;
    lower_index_out[idx] = -1;
    lower_value_out[idx] = 0.0;
  } else {
    switch_out[idx] = 0;
    long assign = assigns[idx];
    int ci = center_table_dev[assign];
    costdiff_out[idx] = 0.0;
    lower_index_out[idx] = ci;
    lower_value_out[idx] = (double)current_cost - (double)x_cost;
  }
}

__global__ static void pgain_apply_kernel(const float *coords,
                                          const float *weights,
                                          float *costs,
                                          long *assigns,
                                          const int *center_table_dev,
                                          const unsigned char *switch_in,
                                          const double *gl_lower_dev,
                                          long x,
                                          int dim,
                                          long n) {
  long idx = (long)blockIdx.x * (long)blockDim.x + (long)threadIdx.x;
  if (idx >= n)
    return;

  long assign = assigns[idx];
  bool close_center = gl_lower_dev[center_table_dev[assign]] > 0.0;
  if (switch_in[idx] || close_center) {
    long base = idx * (long)dim;
    long xbase = x * (long)dim;
    float result = 0.0f;
    for (int j = 0; j < dim; j++) {
      float diff = coords[base + j] - coords[xbase + j];
      result += diff * diff;
    }
    costs[idx] = weights[idx] * result;
    assigns[idx] = x;
  }
}

